VALUES
  ('diplomatic-9e854390-moex-00196', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-112-c655adf3', 'sub-diplomatic-9e854390-03', NULL, 'single_choice', '依司法院釋字第803號解釋，關於原住民文化受憲法保護，下列敘述何者正確？', '["屬於個別原住民受憲法第22條保障之基本權利", "原住民有請求國家保障其文化之給付性權利", "涉及人性尊嚴，國家若加以限制，應為國會保留事項", "國家若為保護環境生態，而限制原住民狩獵文化權，司法應採合理標準予以審查"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:30+00:00", "source_pdf_sha1": "08ce77db5d69", "answer_pdf_sha1": "e245cea2e766", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "201", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00197', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-112-c655adf3', 'sub-diplomatic-9e854390-03', NULL, 'single_choice', '依憲法及增修條文規定，關於行政院組織，下列敘述何者錯誤？', '["行政院雖設有行政院會議，但實質上採取首長制", "基於法律保留原則，包括行政院及所屬機關之組織法規，均僅得以國會立法形式為之", "憲法增修條文對總統及行政院院長之權力雖有修正，在憲法本文中仍規定行政院為國家行政機關", "憲法增修條文變更憲法本文規定，賦予總統直接任命行政院院長之權力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:30+00:00", "source_pdf_sha1": "08ce77db5d69", "answer_pdf_sha1": "e245cea2e766", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "201", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00198', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-112-c655adf3', 'sub-diplomatic-9e854390-03', NULL, 'single_choice', '在權力分立下，有關立法權之敘述，下列何者正確？', '["立法院為國家最高立法機關，由人民選舉之立法委員組成之", "基於監督與制衡，立法院對行政院所提之預算案，得為必要增加支出之提議", "基於憲法採取的是內閣制，立法委員得兼任官吏", "立法委員之報酬或待遇，得授權以命令之方式規定之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:30+00:00", "source_pdf_sha1": "08ce77db5d69", "answer_pdf_sha1": "e245cea2e766", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "201", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00199', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-112-c655adf3', 'sub-diplomatic-9e854390-03', NULL, 'single_choice', '下列何者不屬於監察院彈劾之對象？', '["司法院院長", "軍人", "地方行政首長", "地方民意代表"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:30+00:00", "source_pdf_sha1": "08ce77db5d69", "answer_pdf_sha1": "e245cea2e766", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "201", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00200', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-112-c655adf3', 'sub-diplomatic-9e854390-03', NULL, 'single_choice', '有關政黨違憲解散之敘述，下列何者錯誤？', '["被解散之政黨，必須其目的或行為危害中華民國存在或自由民主憲政秩序", "須由其他政黨提出聲請", "須經言詞辯論始得判決", "須經憲法法庭審理"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:30+00:00", "source_pdf_sha1": "08ce77db5d69", "answer_pdf_sha1": "e245cea2e766", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "201", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00201', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-112-c655adf3', 'sub-diplomatic-9e854390-03', NULL, 'single_choice', '依憲法訴訟法規定，下列何者為國家最高機關聲請憲法法庭判決之要件？', '["行使職權，適用憲法，發生疑義", "經確定終局裁判", "經行政救濟程序所適用", "行使職權，就所適用之法規範，認有牴觸憲法"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:30+00:00", "source_pdf_sha1": "08ce77db5d69", "answer_pdf_sha1": "e245cea2e766", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "201", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00202', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-112-c655adf3', 'sub-diplomatic-9e854390-03', NULL, 'single_choice', '依司法院大法官解釋，地方制度法有關縣（市）議會正副議長選舉之規定，下列敘述何者錯誤？', '["有關縣（市）議會正副議長選舉以記名投票為之，違背憲法第129條所定各種選舉應以無記名投票 方法行之", "縣（市）議會正副議長之選舉，應有議員、代表總額過半數之出席，以得票達出席總數之過半數者 為當選", "縣（市）議會正副議長之選舉結果無人當選時，應立即舉行第二次投票，以得票較多者為當選；得 票相同者，以抽籤定之", "中央法律要求地方議會應以記名投票方式選舉議長、副議長，並不侵害地方自治"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:30+00:00", "source_pdf_sha1": "08ce77db5d69", "answer_pdf_sha1": "e245cea2e766", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "201", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
